import{_ as t}from"./chunks/demo-doc.NIuiqrK9.js";import{c as d,Q as o,j as r,m as a}from"./chunks/framework.BkjtU8k0.js";const g=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/overview.md","filePath":"guide/overview.md","lastUpdated":1779171725000}'),i={name:"guide/overview.md"};function c(s,e,l,h,n,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>Flyfish Viewer 可以为业务系统快速补齐文件在线预览能力。它不同于依赖后端转码的方案，核心解析和渲染都在浏览器端完成，不会额外占用服务器执行 Office 转 PDF、临时文件清理或异步转换任务。</p><p>这让它特别适合静态部署、内网私有化、低运维成本和多系统复用场景。查看<a href="/guide/quickstart">快速开始</a>可以直接跑通第一个预览示例。</p><h2 id="当前能力" tabindex="-1">当前能力 <a class="header-anchor" href="#当前能力" aria-label="Permalink to &quot;当前能力&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>多格式预览</h3><p>内置 59 个扩展名映射，覆盖 Word、Excel、PowerPoint、PDF、OFD、CAD、Markdown、图片、视频以及代码/文本。</p></div><div class="doc-card"><h3>纯前端渲染</h3><p>大部分格式不需要后端转码服务。业务侧只需要提供可访问 URL、File 或二进制数据包装后的 File。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>PDF、OFD、CAD、Office、Markdown 和代码高亮都按需进入对应预览链路，减少无关格式的加载成本。</p></div><div class="doc-card"><h3>双接入路线</h3><p>Vue3 和 Vue2.7 都有对应 npm 包；跨技术栈或多系统场景可独立部署 Demo 站点并通过 iframe 嵌入。</p></div></div><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>交付边界清楚。</strong> 组件、Demo、文档站、公开成品仓库、npm tarball 和构建脚本都围绕成品交付维护，接入方可以先验收效果再决定集成方式。</li><li><strong>视觉体验更接近真实阅读。</strong> Word 文档使用灰色页面底和白色纸张；PDF 提供缩放、页码、导航窗格和可视宽度自适应，避免打开后内容被挤压或不可读。</li><li><strong>格式策略务实。</strong> OFD 基于 <code>DLTech21/ofd.js</code> 源码链路预览；CAD 支持 DXF，DWG 作为转换提示入口；代码/日志使用 <code>highlight.js</code> 轻量高亮，HTML 按源码展示。</li><li><strong>适合平台复用。</strong> 多个系统可以共用同一套预览站点，只要升级静态资源即可统一更新预览能力。</li><li><strong>Vue2 / Vue3 同步维护。</strong> Vue3 包是 <code>@flyfish-group/file-viewer3@1.0.7</code>，Vue2 包是 <code>@flyfish-group/file-viewer@1.0.7</code>，两条包线保持一致的格式能力和 Demo 体验。</li><li><strong>二开路径明确。</strong> 公开仓库提供成品下载，源码和商业二开通过 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">dev.flyfish.group/shop</a> 自助开通，避免交付渠道混乱。</li></ul><h2 id="关键特性" tabindex="-1">关键特性 <a class="header-anchor" href="#关键特性" aria-label="Permalink to &quot;关键特性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code> 使用 <code>docx-preview</code>，<code>.doc</code> 使用 <code>msdoc-viewer</code>，保留文档页面感</td></tr><tr><td>Excel</td><td>多种表格格式统一进入表格预览链路，保留常见尺寸、合并和样式</td></tr><tr><td>PDF</td><td>基于 <code>pdfjs-dist</code>，支持缩放工具栏、页码状态、导航窗格和宽度适配</td></tr><tr><td>OFD</td><td>使用 <code>DLTech21/ofd.js</code> 源码链路，重型能力按需加载</td></tr><tr><td>CAD</td><td>支持 DXF 图纸预览，提供缩放、平移和图层控制</td></tr><tr><td>代码/文本</td><td>使用 <code>highlight.js</code> 高亮多语言源码、日志、配置和 diff</td></tr><tr><td>图片/视频</td><td>图片使用浏览器原生能力和轻量查看器，MP4 使用原生视频播放</td></tr></tbody></table><h2 id="成品与源码" tabindex="-1">成品与源码 <a class="header-anchor" href="#成品与源码" aria-label="Permalink to &quot;成品与源码&quot;">​</a></h2><p>公开 GitHub 仓库用于分发可直接下载使用的构建产物和示例，不包含源码目录。需要源码、二开包或商业自助开通的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><p>项目遵循 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code> 或 <code>@flyfish-group/file-viewer</code>。如果你基于项目修复了通用问题或增强了通用能力，也欢迎一起贡献。</p><div class="doc-shot"><img src="'+t+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">Word 预览在视觉上回到灰色工作台与白色纸张的阅读模型，用户打开正式文档时会更接近熟悉的文档软件体验。</p></div>',13)])])}const v=d(i,[["render",c]]);export{g as __pageData,v as default};
